code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Button, Badge, Separator, icon } from 'decantr/components';

code.example:
function StatsBar({ stats, actions }) {
  const { div, span } = tags;

  const stat = (ic, label, value) =>
    div({ class: css('_flex _aic _gap2') },
      icon(ic),
      span({ class: css('_textsm _fgmuted') }, label),
      span({ class: css('_textsm _fontBold') }, value)
    );

  return div({ class: css('_flex _aic _jcsb _gap4 _py3 _px4 _bordert _borderb') },
    div({ class: css('_flex _aic _gap6') },
      stat('timer', 'Prep', '15 min'),
      Separator({ orientation: 'vertical' }),
      stat('flame', 'Cook', '30 min'),
      Separator({ orientation: 'vertical' }),
      stat('users', 'Servings', '4'),
      Separator({ orientation: 'vertical' }),
      Badge({ variant: 'success' }, 'Easy')
    ),
    div({ class: css('_flex _gap2') },
      Button({ variant: 'outline', size: 'sm' }, icon('git-fork'), 'Fork'),
      Button({ variant: 'outline', size: 'sm' }, icon('bookmark'), 'Save'),
      Button({ variant: 'outline', size: 'sm' }, icon('share'), 'Share')
    )
  );
}

